#include <bits/stdc++.h>
using namespace std;
long n,q,st[1000010][25],a[1000010];
int fun(int l,int r)
{
	int len=r-l+1;
	int ans=min(st[l][a[len]],st[r-(1<<a[len])+1][a[len]]);
	return ans;
}
int main()
{
    ios::sync_with_stdio(0);
    cin.tie(0),cout.tie(0);
	cin>>n>>q;
	a[0]=-1;
	for(int i=1;i<=n;i++)
	{
		cin>>st[i][0];
		a[i]=a[i/2]+1;
	}
	for(int i=1;i<=a[n];i++)
	{
		for(int j=1;j<=n-i+1;j++)
		{
			st[j][i]=min(st[j][i-1],st[j+(1<<(i-1))][i-1]);
		}
	}
	for(int i=1;i<=q;i++)
	{
		int l,r;
		cin>>l>>r;
		cout<<fun(l,r)<<' ';
	}
	return 0;
}
